import React from "react";
import { Link } from "react-router-dom";
import { FileText, BarChart3, History, Building2, TrendingUp } from "lucide-react";

const Dashboard = () => {
  const features = [
    {
      title: "Módulo A: Facturación General",
      description: "Extrae datos de facturas: proveedor, RIF, fecha, período, sub-total, IVA, monto total, moneda y tipo.",
      icon: FileText,
      link: "/module-a",
      color: "#0033CC",
      testId: "card-module-a"
    },
    {
      title: "Módulo B: Análisis Especializado",
      description: "Procesa documentos complejos: ventas de terceros, telefonía móvil, rentas y servicios, resumen de consumo.",
      icon: BarChart3,
      link: "/module-b",
      color: "#16A34A",
      testId: "card-module-b"
    },
    {
      title: "Historial de Documentos",
      description: "Revisa todos los documentos procesados anteriormente y sus datos extraídos.",
      icon: History,
      link: "/history",
      color: "#EAB308",
      testId: "card-history"
    },
    {
      title: "Centros de Costo",
      description: "Gestiona centros de costo y asigna números móviles para análisis detallado.",
      icon: Building2,
      link: "/cost-centers",
      color: "#DC2626",
      testId: "card-cost-centers"
    },
  ];

  return (
    <div className="space-y-6">
      {/* Hero Section */}
      <div className="bg-white border border-zinc-200 rounded-none p-8">
        <div className="flex items-start justify-between">
          <div>
            <h1 className="font-heading text-4xl font-bold text-[#09090B] tracking-tight mb-3">
              Sistema de Extracción Inteligente de Datos
            </h1>
            <p className="text-lg text-zinc-600 leading-relaxed max-w-3xl">
              Procesa documentos de facturación y documentos complejos utilizando IA (Gemini 3 Flash) para extraer información clave sin plantillas fijas.
            </p>
          </div>
          <TrendingUp className="w-16 h-16 text-[#0033CC]" strokeWidth={1.5} />
        </div>
      </div>

      {/* Features Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {features.map((feature) => {
          const Icon = feature.icon;
          return (
            <Link
              key={feature.link}
              to={feature.link}
              data-testid={feature.testId}
              className="bg-white border border-zinc-200 rounded-none p-6 hover:border-[#0033CC] transition-colors group"
            >
              <div className="flex items-start gap-4">
                <div className="p-3 bg-zinc-50 border border-zinc-200">
                  <Icon className="w-6 h-6" style={{ color: feature.color }} strokeWidth={1.5} />
                </div>
                <div className="flex-1">
                  <h3 className="font-heading text-lg font-bold text-[#09090B] mb-2 group-hover:text-[#0033CC] transition-colors">
                    {feature.title}
                  </h3>
                  <p className="text-sm text-zinc-600 leading-relaxed">
                    {feature.description}
                  </p>
                </div>
              </div>
            </Link>
          );
        })}
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white border border-zinc-200 rounded-none p-6">
          <p className="text-xs font-semibold uppercase tracking-wider text-zinc-500 mb-2">
            Formatos Soportados
          </p>
          <p className="font-heading text-3xl font-bold text-[#09090B] mb-1">4</p>
          <p className="text-sm text-zinc-600">PDF, Imágenes, Word, Excel</p>
        </div>
        <div className="bg-white border border-zinc-200 rounded-none p-6">
          <p className="text-xs font-semibold uppercase tracking-wider text-zinc-500 mb-2">
            Motor de IA
          </p>
          <p className="font-heading text-3xl font-bold text-[#09090B] mb-1">Gemini</p>
          <p className="text-sm text-zinc-600">3 Flash - Análisis rápido y preciso</p>
        </div>
        <div className="bg-white border border-zinc-200 rounded-none p-6">
          <p className="text-xs font-semibold uppercase tracking-wider text-zinc-500 mb-2">
            Exportación
          </p>
          <p className="font-heading text-3xl font-bold text-[#09090B] mb-1">Excel</p>
          <p className="text-sm text-zinc-600">Descarga directa estructurada</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
